DEFAULT_TIMEOUT = 30
DEFAULT_RETRIES = 3


class ClientConfig:
    def __init__(self):
        self.connect_timeout = 30
        self.read_timeout = 60
        self.max_retries = 3
        self.backoff_factor = 0.5
        self.pool_size = 10
        self.verify_ssl = True

    def as_dict(self):
        return vars(self)
